#include<bits/stdc++.h>
using namespace std;
int n,tot,ans;
struct node
{
    int son[26],cnt;
}t[3000010];
int dp[3000010];
char s[500010];
void insert(char s[])
{
    int p=0;
    for(int i=strlen(s+1);i>=1;i--)
    {
        int k=s[i]-'a';
        if(!t[p].son[k])
        {
            t[p].son[k]=++tot;
        }
        p=t[p].son[k];
    }
    t[p].cnt++;
}
void dfs(int x)
{
    int siz=0,max1=0,max2=0;
    for(int i=0;i<26;i++)
    {
        int v=t[x].son[i];
        if(v)
        {
            dfs(v);
            siz+=t[v].cnt;
            if(dp[v]>max1)
            {
                max2=max1;
                max1=dp[v];
            }
            else if(dp[v]>max2)
            {
                max2=dp[v];
            }
        }
    }
    if(t[x].cnt)
    {
        dp[x]=max1+max(siz,1);
    }
    ans=max(ans,max1+max2+t[x].cnt+max(siz-2,0));
}
int main()
{
    scanf("%d",&n);
    for(int i=1;i<=n;i++)
    {
        scanf("%s",s+1);
        insert(s);
    }
    dfs(0);
    printf("%d",ans);
    return 0;
}
